					in power = vehiclePower;
					in mass = vehicleMass;
					in delta_t = deltaT;
					in x_in = position;
					in v_in = speed;
					out x_out;
					out v_out;
				}
				then assign position := dynamics.x_out;
				then assign speed := dynamics.v_out;
				then assign positionsOut := positionsOut->including(position);
